import React, { useState } from 'react';
import styled from 'styled-components';
import { motion } from 'framer-motion';

const NewsContainer = styled.div`
  max-width: 1400px;
  margin: 0 auto;
  padding: 8rem 2rem 4rem;
`;

const HeaderSection = styled(motion.div)`
  margin-bottom: 6rem;
  display: flex;
  justify-content: space-between;
  align-items: flex-end;

  @media (max-width: 768px) {
    flex-direction: column;
    align-items: flex-start;
    gap: 2rem;
  }
`;

const TitleWrapper = styled.div`
  h1 {
    font-size: clamp(3rem, 8vw, 6rem);
    font-weight: 950;
    line-height: 0.9;
    letter-spacing: -4px;
    background: linear-gradient(135deg, #fff 0%, rgba(255, 255, 255, 0.4) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    text-transform: uppercase;
  }
`;

const FeaturedCard = styled(motion.div)`
  grid-column: span 12;
  background: rgba(255, 255, 255, 0.02);
  backdrop-filter: blur(20px);
  border: 1px solid rgba(255, 255, 255, 0.05);
  border-radius: 48px;
  padding: 4rem;
  margin-bottom: 4rem;
  display: grid;
  grid-template-columns: 1.5fr 1fr;
  gap: 4rem;
  position: relative;
  overflow: hidden;

  &::before {
    content: '';
    position: absolute;
    top: 0;
    right: 0;
    width: 100%;
    height: 100%;
    background: radial-gradient(circle at 100% 0%, rgba(0, 242, 254, 0.1) 0%, transparent 50%);
    pointer-events: none;
  }

  @media (max-width: 1024px) {
    grid-template-columns: 1fr;
    padding: 2.5rem;
  }
`;

const FeedGrid = styled(motion.div)`
  display: grid;
  grid-template-columns: repeat(12, 1fr);
  gap: 2rem;
`;

const NewsCard = styled(motion.div)`
  grid-column: span 4;
  background: rgba(255, 255, 255, 0.02);
  backdrop-filter: blur(20px);
  border: 1px solid rgba(255, 255, 255, 0.05);
  border-radius: 32px;
  padding: 2.5rem;
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
  transition: all 0.4s cubic-bezier(0.16, 1, 0.3, 1);
  cursor: pointer;

  &:hover {
    background: rgba(255, 255, 255, 0.04);
    border-color: rgba(0, 242, 254, 0.2);
    transform: translateY(-10px);
    box-shadow: 0 20px 40px rgba(0, 0, 0, 0.3);
  }

  @media (max-width: 1024px) { grid-column: span 6; }
  @media (max-width: 640px) { grid-column: span 12; }
`;

const CategoryBadge = styled.span`
  font-size: 0.65rem;
  font-weight: 900;
  letter-spacing: 2px;
  color: #00f2fe;
  text-transform: uppercase;
  padding: 0.4rem 1rem;
  background: rgba(0, 242, 254, 0.1);
  border-radius: 100px;
  width: fit-content;
`;

const News: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('All');
  const categories = ['All', 'Markets', 'Commodities', 'Economy', 'Analysis', 'Education'];

  const filteredNews = newsItems.filter(item => {
    const matchesSearch = item.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
                         item.content.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesCategory = selectedCategory === 'All' || item.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  return (
    <NewsContainer>
      <HeaderSection
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8 }}
      >
        <TitleWrapper>
          <h1>Feeds</h1>
          <input
            type="text"
            placeholder="Search Articles..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            style={{
              background: 'rgba(255, 255, 255, 0.02)',
              border: '1px solid rgba(255, 255, 255, 0.1)',
              borderRadius: '100px',
              padding: '0.6rem 1.5rem',
              color: 'rgba(255, 255, 255, 0.8)',
              fontSize: '0.7rem',
              fontWeight: 900,
              letterSpacing: '1px',
              textTransform: 'uppercase',
              outline: 'none',
              marginTop: '2rem',
              width: '100%',
              maxWidth: '400px',
              boxSizing: 'border-box',
            }}
          />
        </TitleWrapper>
        <div style={{ display: 'flex', gap: '1rem', flexWrap: 'wrap' }}>
          {categories.map(cat => (
            <motion.button
              key={cat}
              onClick={() => setSelectedCategory(cat)}
              style={{
                background: selectedCategory === cat ? 'rgba(0, 242, 254, 0.1)' : 'transparent',
                color: selectedCategory === cat ? '#00f2fe' : 'rgba(255,255,255,0.4)',
                border: `1px solid ${selectedCategory === cat ? 'rgba(0, 242, 254, 0.3)' : 'rgba(255,255,255,0.1)'}`,
                padding: '0.6rem 1.5rem',
                borderRadius: '100px',
                fontSize: '0.7rem',
                fontWeight: 900,
                letterSpacing: '1px',
                textTransform: 'uppercase',
                cursor: 'pointer'
              }}
              whileHover={{ scale: 1.05, background: 'rgba(255,255,255,0.05)' }}
              whileTap={{ scale: 0.95 }}
            >
              {cat}
            </motion.button>
          ))}
        </div>
      </HeaderSection>

      <FeaturedCard
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        transition={{ duration: 1, delay: 0.2 }}
      >
        <div>
          <CategoryBadge>Strategic Analysis</CategoryBadge>
          <h2 style={{ fontSize: '3rem', fontWeight: 950, margin: '2rem 0', lineHeight: 1, letterSpacing: '-2px' }}>
            THE NEURAL ARCHITECTURE OF MODERN PORTFOLIOS
          </h2>
          <p style={{ fontSize: '1.1rem', color: 'rgba(255,255,255,0.5)', lineHeight: 1.6, marginBottom: '3rem' }}>
            Deep dive into the algorithmic shifts governing institutional asset allocation in the age of autonomous finance.
          </p>
          <motion.button
            style={{
              background: 'linear-gradient(135deg, #00f2fe 0%, #4facfe 100%)',
              border: 'none',
              padding: '1rem 2.5rem',
              borderRadius: '100px',
              fontWeight: 900,
              fontSize: '0.8rem',
              letterSpacing: '1px',
              textTransform: 'uppercase',
              cursor: 'pointer',
              color: '#000'
            }}
            whileHover={{ scale: 1.05, boxShadow: '0 0 30px rgba(0, 242, 254, 0.4)' }}
          >
            Access Intelligence
          </motion.button>
        </div>
        <div style={{ 
          background: 'rgba(255,255,255,0.02)', 
          borderRadius: '32px',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          fontSize: '5rem',
          border: '1px solid rgba(255,255,255,0.05)'
        }}>
          💎
        </div>
      </FeaturedCard>

      <FeedGrid
        layout
        initial={{ opacity: 0, y: 40 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8, delay: 0.4 }}
      >
        {filteredNews.map((item, idx) => (
          <NewsCard
            key={idx}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.5 + idx * 0.1 }}
          >
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <CategoryBadge>{item.category}</CategoryBadge>
              <span style={{ fontSize: '0.7rem', fontWeight: 800, color: 'rgba(255,255,255,0.3)' }}>{item.date}</span>
            </div>
            <h3 style={{ fontSize: '1.4rem', fontWeight: 900, lineHeight: 1.2, letterSpacing: '-0.5px' }}>{item.title}</h3>
            <p style={{ fontSize: '0.9rem', color: 'rgba(255,255,255,0.4)', lineHeight: 1.6, flexGrow: 1 }}>{item.content}</p>
            <div style={{ paddingTop: '1.5rem', borderTop: '1px solid rgba(255,255,255,0.05)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <span style={{ fontSize: '0.75rem', fontWeight: 900, color: '#00f2fe' }}>READ PROTOCOL</span>
              <span style={{ fontSize: '1rem' }}>→</span>
            </div>
          </NewsCard>
        ))}
      </FeedGrid>
    </NewsContainer>
  );
};

const newsItems = [
  {
    title: '📈 Stock Market Hits All-Time High',
    content: 'Major indices reached record levels as investor confidence grows amid economic recovery. Market sentiment remains bullish with strong institutional buying.',
    date: 'March 4, 2026',
    category: 'Markets',
